// ── MERGE ALL POSTS INTO blogPosts.ts ───────────────────────────────────────

const allNewPosts = [
  ...countyPosts,
  ...oilHeatPosts,
  ...commercialPosts,
  ...psegPosts,
  ...seasonalPosts,
  ...cityPosts,
  ...generalPosts,
];

// Serialize one post to TS code
function serializePost(p: Post): string {
  const secs = p.sections.map(s => {
    if (s.type === "cta_box") {
      return `      { type: "cta_box", content: ${JSON.stringify(s.content)}, buttonText: ${JSON.stringify(s.buttonText)}, buttonUrl: ${JSON.stringify(s.buttonUrl)} }`;
    }
    if (s.items) {
      return `      { type: ${JSON.stringify(s.type)}, items: ${JSON.stringify(s.items)} }`;
    }
    return `      { type: ${JSON.stringify(s.type)}, content: ${JSON.stringify(s.content)} }`;
  }).join(",\n");

  return `  {
    title: ${JSON.stringify(p.title)},
    slug: ${JSON.stringify(p.slug)},
    date: ${JSON.stringify(p.date)},
    readTime: ${JSON.stringify(p.readTime)},
    category: ${JSON.stringify(p.category)},
    metaDescription: ${JSON.stringify(p.metaDescription)},
    excerpt: ${JSON.stringify(p.excerpt)},
    sections: [
${secs},
    ],
  }`;
}

// Read existing file
let content = fs.readFileSync(BLOG_FILE, "utf-8");

// Find the closing ];
const closingIdx = content.lastIndexOf("];");
if (closingIdx === -1) {
  console.error("Could not find closing ]; in blogPosts.ts");
  process.exit(1);
}

// Generate new post code
const newPostsCode = allNewPosts.map(serializePost).join(",\n");

// Insert before ];
content = content.substring(0, closingIdx) + ",\n" + newPostsCode + ",\n" + content.substring(closingIdx);

fs.writeFileSync(BLOG_FILE, content, "utf-8");
